package com.example.myapp

import android.app.Activity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import android.widget.TextView
import android.widget.Toast

// DeepLinkHandlerActivity - Entry point for all deep links
class DeepLinkHandlerActivity : Activity() {

    companion object {
        private const val TAG = "DeepLinkHandler"
        const val SCHEME = "myapp"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val uri = intent?.data

        if (uri == null || uri.scheme != SCHEME) {
            Log.e(TAG, "Invalid deep link: $uri")
            Toast.makeText(this, "Invalid link", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        Log.d(TAG, "Handling deep link: $uri")

        val handled = DeepLinkRouter.route(this, uri)

        if (!handled) {
            Log.w(TAG, "Unhandled deep link: $uri")
            Toast.makeText(this, "Unknown link: $uri", Toast.LENGTH_SHORT).show()
            // Navigate to main activity as fallback
            val fallbackIntent = Intent(this, MainActivity::class.java)
            fallbackIntent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
            startActivity(fallbackIntent)
        }

        finish()
    }
}

// DeepLinkRouter - Parses URI and routes to appropriate Activity
object DeepLinkRouter {

    private const val TAG = "DeepLinkRouter"

    fun route(activity: Activity, uri: Uri): Boolean {
        val pathSegments = uri.pathSegments

        if (pathSegments.isEmpty()) {
            return false
        }

        return when (pathSegments[0]) {
            "profile" -> handleProfileDeepLink(activity, uri, pathSegments)
            "payment" -> handlePaymentDeepLink(activity, uri, pathSegments)
            "settings" -> handleSettingsDeepLink(activity, uri)
            "promo" -> handlePromoDeepLink(activity, uri)
            else -> false
        }
    }

    private fun handleProfileDeepLink(activity: Activity, uri: Uri, pathSegments: List<String>): Boolean {
        if (pathSegments.size < 2) {
            Log.w(TAG, "Profile deep link missing user ID")
            return false
        }

        val userId = pathSegments[1]
        val source = uri.getQueryParameter("source") // e.g., myapp://profile/123?source=email_campaign

        val intent = Intent(activity, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_USER_ID, userId)
            source?.let { putExtra(ProfileActivity.EXTRA_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }

        Log.d(TAG, "Navigating to ProfileActivity with userId=$userId, source=$source")
        activity.startActivity(intent)
        return true
    }

    private fun handlePaymentDeepLink(activity: Activity, uri: Uri, pathSegments: List<String>): Boolean {
        if (pathSegments.size < 2) {
            Log.w(TAG, "Payment deep link missing action")
            return false
        }

        val action = pathSegments[1] // e.g., "confirm", "history", "refund"
        val transactionId = uri.getQueryParameter("transaction_id")
        val amount = uri.getQueryParameter("amount")
        val source = uri.getQueryParameter("source")

        val intent = Intent(activity, PaymentActivity::class.java).apply {
            putExtra(PaymentActivity.EXTRA_ACTION, action)
            transactionId?.let { putExtra(PaymentActivity.EXTRA_TRANSACTION_ID, it) }
            amount?.let { putExtra(PaymentActivity.EXTRA_AMOUNT, it) }
            source?.let { putExtra(PaymentActivity.EXTRA_SOURCE, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }

        Log.d(TAG, "Navigating to PaymentActivity with action=$action, transactionId=$transactionId")
        activity.startActivity(intent)
        return true
    }

    private fun handleSettingsDeepLink(activity: Activity, uri: Uri): Boolean {
        val section = uri.getQueryParameter("section")

        val intent = Intent(activity, SettingsActivity::class.java).apply {
            section?.let { putExtra(SettingsActivity.EXTRA_SECTION, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }

        activity.startActivity(intent)
        return true
    }

    private fun handlePromoDeepLink(activity: Activity, uri: Uri): Boolean {
        val promoCode = uri.getQueryParameter("code")
        val campaignId = uri.getQueryParameter("campaign_id")

        val intent = Intent(activity, PromoActivity::class.java).apply {
            promoCode?.let { putExtra(PromoActivity.EXTRA_PROMO_CODE, it) }
            campaignId?.let { putExtra(PromoActivity.EXTRA_CAMPAIGN_ID, it) }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }

        activity.startActivity(intent)
        return true
    }
}

