// DeepLinkBuilder - Utility to construct deep link URIs for campaigns
object DeepLinkBuilder {

    fun buildProfileLink(userId: String, source: String? = null): Uri {
        return Uri.Builder()
            .scheme(DeepLinkHandlerActivity.SCHEME)
            .authority("")
            .appendPath("profile")
            .appendPath(userId)
            .apply { source?.let { appendQueryParameter("source", it) } }
            .build()
    }

    fun buildPaymentConfirmLink(transactionId: String, amount: String? = null, source: String? = null): Uri {
        return Uri.Builder()
            .scheme(DeepLinkHandlerActivity.SCHEME)
            .authority("")
            .appendPath("payment")
            .appendPath("confirm")
            .appendQueryParameter("transaction_id", transactionId)
            .apply {
                amount?.let { appendQueryParameter("amount", it) }
                source?.let { appendQueryParameter("source", it) }
            }
            .build()
    }

    fun buildPromoLink(promoCode: String, campaignId: String): Uri {
        return Uri.Builder()
            .scheme(DeepLinkHandlerActivity.SCHEME)
            .authority("")
            .appendPath("promo")
            .appendQueryParameter("code", promoCode)
            .appendQueryParameter("campaign_id", campaignId)
            .build()
    }
}